// HasAiWebPage applies the HasEdge predicate on the "ai_web_page" edge.
func HasAiWebPage() predicate.AiChatMessage {
	return predicate.AiChatMessage(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.O2M, false, AiWebPageTable, AiWebPageColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasAiWebPageWith applies the HasEdge predicate on the "ai_web_page" edge with a given conditions (other predicates).
func HasAiWebPageWith(preds ...predicate.AiWebPage) predicate.AiChatMessage {
	return predicate.AiChatMessage(func(s *sql.Selector) {
		step := newAiWebPageStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.AiChatMessage) predicate.AiChatMessage {
	return predicate.AiChatMessage(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.AiChatMessage) predicate.AiChatMessage {
	return predicate.AiChatMessage(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.AiChatMessage) predicate.AiChatMessage {
	return predicate.AiChatMessage(sql.NotPredicates(p))
}
